using System;
using System.Threading.Tasks;
using Microsoft.EntityFrameworkCore;
using System.Transactions;

public class EventBookingContext : DbContext
{
    public DbSet<Event> Events { get; set; }
}

public class Event
{
    public int Id { get; set; }
    public string Name { get; set; }
    public int AvailableSeats { get; set; }
}

public class TicketPurchaseService
{
    private readonly EventBookingContext _context;

    public TicketPurchaseService(EventBookingContext context)
    {
        _context = context;
    }

    public async Task<bool> PurchaseTicketsAsync(int eventId, int quantity)
    {
        using (var transactionScope = new TransactionScope(TransactionScopeOption.Required))
        {
            try
            {
                var eventEntity = await _context.Events.FindAsync(eventId);
                if (eventEntity == null || eventEntity.AvailableSeats < quantity)
                {
                    return false;
                }

                // Use a lock to ensure atomicity of read-modify-write flow
                using (var locker = new object())
                {
                    lock (locker)
                    {
                        if (eventEntity.AvailableSeats >= quantity)
                        {
                            eventEntity.AvailableSeats -= quantity;

                            await _context.SaveChangesAsync();

                            transactionScope.Complete();
                            return true;
                        }
                        else
                        {
                            return false;
                        }
                    }
                }
            }
            catch (Exception ex)
            {
                Console.WriteLine($"Error purchasing tickets: {ex.Message}");
                throw;
            }
        }

        return false;
    }
}